SELECT 
FROM code_mapping
WHERE p0_table_name = #{p0TableName}
AND p0_row_id = #{p0RowId}
ORDER BY target_type

SELECT 
FROM code_mapping
WHERE target_type = #{targetType}
AND target_id = #{targetId}
ORDER BY p0_table_name, p0_row_id

SELECT FROM code_mapping
AND p0_table_name LIKE CONCAT('%', #{p0TableName}, '%')
AND p0_material_name LIKE CONCAT('%', #{p0MaterialName}, '%')
AND target_type = #{targetType}
AND match_type = #{matchType}
ORDER BY p0_table_name, p0_row_id
